"""
Installation helper script for the data processing pipeline.

This script automates the setup process, ensuring that both public
and private package indices are properly configured before installing
dependencies.

Usage:
    python install.py [--env-name <name>] [--private-pypi-url <url>]
"""

import subprocess
import sys
import os
import argparse
import getpass
from pathlib import Path


# Default configuration
DEFAULT_PRIVATE_PYPI_URL = "https://pypi.company.com/simple/"
DEFAULT_PUBLIC_PYPI_URL = "https://pypi.org/simple/"
DEFAULT_VENV_NAME = ".venv"


def parse_args():
    parser = argparse.ArgumentParser(
        description="Install data processing pipeline dependencies"
    )
    parser.add_argument(
        "--env-name",
        default=DEFAULT_VENV_NAME,
        help=f"Virtual environment name (default: {DEFAULT_VENV_NAME})",
    )
    parser.add_argument(
        "--private-pypi-url",
        default=os.environ.get("PRIVATE_PYPI_URL", DEFAULT_PRIVATE_PYPI_URL),
        help=f"Private PyPI server URL (default: {DEFAULT_PRIVATE_PYPI_URL})",
    )
    parser.add_argument(
        "--with-auth",
        action="store_true",
        help="Prompt for private PyPI credentials",
    )
    parser.add_argument(
        "--dev",
        action="store_true",
        help="Install development dependencies as well",
    )
    parser.add_argument(
        "--skip-venv",
        action="store_true",
        help="Skip virtual environment creation",
    )
    return parser.parse_args()


def create_virtual_environment(env_name):
    """Create a virtual environment if it doesn't exist."""
    venv_path = Path(env_name)
    if venv_path.exists():
        print(f"Virtual environment '{env_name}' already exists. Skipping creation.")
        return venv_path

    print(f"Creating virtual environment: {env_name}")
    subprocess.check_call([sys.executable, "-m", "venv", env_name])
    print(f"Virtual environment created at: {venv_path.resolve()}")
    return venv_path


def get_pip_executable(env_name):
    """Get the pip executable path within the virtual environment."""
    if sys.platform == "win32":
        pip_path = Path(env_name) / "Scripts" / "pip"
    else:
        pip_path = Path(env_name) / "bin" / "pip"
    return str(pip_path)


def get_python_executable(env_name):
    """Get the python executable path within the virtual environment."""
    if sys.platform == "win32":
        python_path = Path(env_name) / "Scripts" / "python"
    else:
        python_path = Path(env_name) / "bin" / "python"
    return str(python_path)


def build_private_pypi_url(base_url, with_auth):
    """Build the private PyPI URL, optionally with embedded credentials."""
    if not with_auth:
        return base_url

    print("\n--- Private PyPI Authentication ---")
    username = input("Username: ").strip()
    password = getpass.getpass("Password/Token: ").strip()

    # Embed credentials in the URL: https://user:pass@host/path
    if "://" in base_url:
        scheme, rest = base_url.split("://", 1)
        authenticated_url = f"{scheme}://{username}:{password}@{rest}"
    else:
        authenticated_url = f"https://{username}:{password}@{base_url}"

    return authenticated_url


def configure_pip_conf(env_name, private_pypi_url):
    """Write a pip.conf inside the virtual environment for dual-source resolution."""
    if sys.platform == "win32":
        pip_conf_path = Path(env_name) / "pip.ini"
    else:
        pip_conf_path = Path(env_name) / "pip.conf"

    # Extract host for trusted-host
    from urllib.parse import urlparse
    parsed = urlparse(private_pypi_url)
    trusted_host = parsed.hostname or "pypi.company.com"

    pip_conf_content = f"""[global]
index-url = {DEFAULT_PUBLIC_PYPI_URL}
extra-index-url = {private_pypi_url}
trusted-host = {trusted_host}

[install]
timeout = 120
retries = 5
"""
    pip_conf_path.write_text(pip_conf_content)
    print(f"Wrote pip configuration to: {pip_conf_path}")


def upgrade_pip(pip_executable):
    """Upgrade pip to the latest version."""
    print("Upgrading pip...")
    subprocess.check_call([pip_executable, "install", "--upgrade", "pip", "setuptools", "wheel"])


def install_requirements(pip_executable, private_pypi_url, dev=False):
    """Install project dependencies from requirements.txt using dual index sources."""
    from urllib.parse import urlparse
    parsed = urlparse(private_pypi_url)
    trusted_host = parsed.hostname or "pypi.company.com"

    # Base install command with dual sources
    cmd = [
        pip_executable,
        "install",
        "--index-url", DEFAULT_PUBLIC_PYPI_URL,
        "--extra-index-url", private_pypi_url,
        "--trusted-host", trusted_host,
    ]

    # Install from requirements.txt if it exists
    requirements_file = Path("requirements.txt")
    if requirements_file.exists():
        print(f"\nInstalling dependencies from {requirements_file}...")
        subprocess.check_call(cmd + ["-r", str(requirements_file)])
    else:
        print(f"\n{requirements_file} not found. Installing from setup.py/pyproject.toml...")
        install_cmd = cmd + ["-e", "."]
        if dev:
            install_cmd = cmd + ["-e", ".[dev]"]
        subprocess.check_call(install_cmd)
        return

    # Install dev extras if requested
    if dev:
        print("\nInstalling development dependencies...")
        dev_requirements = Path("requirements-dev.txt")
        if dev_requirements.exists():
            subprocess.check_call(cmd + ["-r", str(dev_requirements)])
        else:
            # Fall back to setup.py/pyproject.toml extras
            subprocess.check_call(cmd + ["-e", ".[dev]"])


def verify_installation(pip_executable):
    """Verify that critical packages are installed."""
    print("\n--- Verifying Installation ---")
    critical_packages = [
        "pandas",
        "numpy",
        "requests",
        "company-analytics",
        "company-ml-models",
    ]

    result = subprocess.run(
        [pip_executable, "list", "--format=columns"],
        capture_output=True,
        text=True,
    )
    installed = result.stdout.lower()

    all_ok = True
    for pkg in critical_packages:
        normalized = pkg.lower().replace("-", "_").replace(" ", "_")
        if normalized in installed.replace("-", "_"):
            print(f"  ✓ {pkg} installed")
        else:
            print(f"  ✗ {pkg} NOT FOUND")
            all_ok = False

    if all_ok:
        print("\nAll critical packages installed successfully!")
    else:
        print("\nWARNING: Some packages could not be verified.")
        print("Check your private PyPI server connectivity and credentials.")

    return all_ok


def main():
    args = parse_args()

    print("=" * 60)
    print("  Data Processing Pipeline - Dependency Installer")
    print("=" * 60)
    print(f"\nPublic PyPI:  {DEFAULT_PUBLIC_PYPI_URL}")
    print(f"Private PyPI: {args.private_pypi_url}")
    print(f"Dev mode:     {args.dev}")
    print()

    # Build authenticated URL if needed
    private_pypi_url = build_private_pypi_url(args.private_pypi_url, args.with_auth)

    if not args.skip_venv:
        # Step 1: Create virtual environment
        create_virtual_environment(args.env_name)
        pip_executable = get_pip_executable(args.env_name)

        # Step 2: Configure pip.conf in the venv
        configure_pip_conf(args.env_name, private_pypi_url)
    else:
        pip_executable = "pip"
        print("Skipping virtual environment creation. Using system pip.")

    # Step 3: Upgrade pip
    upgrade_pip(pip_executable)

    # Step 4: Install dependencies
    install_requirements(pip_executable, private_pypi_url, dev=args.dev)

    # Step 5: Verify installation
    verify_installation(pip_executable)

    if not args.skip_venv:
        python_executable = get_python_executable(args.env_name)
        print(f"\nTo activate the environment:")
        if sys.platform == "win32":
            print(f"  {args.env_name}\\Scripts\\activate")
        else:
            print(f"  source {args.env_name}/bin/activate")
        print(f"\nThen run: run-pipeline")

    print("\nInstallation complete!")


if __name__ == "__main__":
    main()